  ('real-estate-moex-01442', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '甲君將其所有一棟透天厝以1,275萬元賣給其小舅子，經判斷比正常價格便宜一成五。試問在其他條件不 變下，其正常價格應為多少？', '["1,083.75萬元", "1,147.5萬元", "1,500萬元", "1,416.7萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01443', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '一比較標的於102年8月以1,000萬元成交，當時的價格指數為90%；勘估標的價格日期104年8月當期 之價格指數為95%。假設其他條件相同，試問該勘估標的經價格日期調整後之價格約為多少？', '["947.37萬元", "950.00萬元", "1,000.00萬元", "l,055.56萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01444', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '依不動產估價技術規則之規定，下列有關比較法個別因素調整及試算價格求取之敘述，何者正確？', '["就勘估標的與比較標的差異進行價格調整時，以差額法為原則", "就勘估標的與比較標的差異進行價格調整時，以定性分析法為原則", "偏高或偏低檢討後試算價格間差距仍達百分之十以上者，應排除該試算價格之適用", "偏高或偏低檢討後試算價格間差距仍達百分之二十以上者，應排除該試算價格之適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01445', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '依不動產估價技術規則之規定，以不動產證券化為估價目的，採折現現金流量分析法估價時，各期淨收 益應以下列何者為計算原則？', '["勘估標的之契約租金", "勘估標的之經濟租金", "比較標的之契約租金", "比較標的之經濟租金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01446', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '某不動產之總收益為200萬元，若總費用為總收益的30%，資本化率為5%，則該不動產之純收益應為多 少？', '["60萬元", "70萬元", "130萬元", "140萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01447', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '下列有關直接資本化法計算收益價格公式之敘述，何者正確？', '["勘估標的未來平均一年期間之客觀總收益 ×收益資本化率", "勘估標的未來平均一年期間之客觀總收益 ÷收益資本化率", "勘估標的過去平均一年期間之客觀總收益 ×收益資本化率", "勘估標的過去平均一年期間之客觀總收益 ÷收益資本化率"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01448', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '下列有關收益法估價程序的排列，何者正確？①計算淨收益  ②推算總費用  ③計算收益價格  ④推 算有效總收入  ⑤決定收益資本化率  ⑥蒐集收入、費用及資本化率等資料', '["⑤⑥", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
