  ('real-estate-moex-01450', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '建物估價以求取重建成本為原則，但建物使用之材料目前已無生產或施工方法已改變者，得採取下列何 種成本替代之？', '["毛胚成本", "比較成本", "重置成本", "總體成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
